import React, { useState, useEffect } from 'react'
import { useHistory, useParams } from 'react-router-dom'
import styled from 'styled-components'
import './Detail.scss'

let Box = styled.div`
  padding: 30px;
`
let Title = styled.h4`
  font-size: 25px;
  color: ${props => props.color}
`

function Detail(props) {
  let [isVisibleAlert, onChangeIsVisibleAlert] = useState(true)

  useEffect(() => { // 컴포넌트가 mount 되었을 때, 컴포넌트가 update 될 때
    console.log("hello world!")
    let timer = setTimeout(() => { onChangeIsVisibleAlert(false) }, 2000)
    return () => { clearTimeout(timer) }
  }, [isVisibleAlert])

  let { id } = useParams()
  let history = useHistory()

  let item = props.items.find((item) => {
    return item.id == id
  })

  return (
    <div className="container">
      <Box>
        <Title className="red">상세페이지</Title>
      </Box>
      {
        isVisibleAlert
          ? (
            <div className="my-alert2">
              <p>재고가 얼마 남지 않았습니다.</p>
            </div>
          )
          : null
      }

      <div className="row">
        <div className="col-md-6">
          <img src={item.imageUrl} width="100%" />
        </div>
        <div className="col-md-6 mt-4">
          <h4 className="pt-5">{item.title}</h4>
          <p>{item.content}</p>
          <p>{item.price}</p>
          <Stock stock={props.stocks[id]} />
          <button className="btn btn-danger" onClick={() => {
            let newAry = [...props.stocks]
            newAry[id] = props.stocks[id] - 1
            props.onChangeStocks(newAry)
          }}>주문하기</button>
          &nbsp;
          <button className="btn btn-danger" onClick={() => {
            history.goBack()
            // history.push('/')
          }}>뒤로가기</button>
        </div>
      </div>
    </div>
  )
}

function Stock(props) {
  return (
    <p>재고: {props.stock}</p>
  )
}

export default Detail